const express = require('express');
const multer = require('multer');
const fs = require('fs-extra');
const path = require('path');

const app = express();

app.use(express.static('public'));
app.use(express.json());

const upload = multer({
    dest: 'uploads/',
    limits: { fileSize: 0 },
});

const fileFormats = {
    image: ['jpg', 'png', 'gif', 'svg'],
    document: ['pdf', 'doc', 'docx'],
    archive: ['zip'],
};

const generateThumbnail = (filename, mimetype) => {
    if (fileFormats.image.includes(path.extname(filename).slice(1))) {
        const fileBuffer = fs.readFileSync(`uploads/${filename}`);
        const image = Buffer.from(fileBuffer.toString('base64'), 'base64');
        const thumbnailPath = path.join('public/uploads/thumbnails', filename);
        const thumbFilename = `thumb_${filename}`;
        const img = new Jimp(image, (err, image) => {
            if (err) console.log(err);
            else image.resize(200, 200).write(thumbnailPath);
        });
    }
};

const saveFile = async (req, res) => {
    try {
        await fs.rename(`uploads/${req.file.filename}`, `uploads/${req.file.originalname}`);
        generateThumbnail(req.file.originalname, req.file.mimetype);

        if (fileFormats.image.includes(path.extname(req.file.originalname).slice(1))) {
            const img = new Jimp(fs.readFileSync(`uploads/${req.file.originalname}`), (err, image) => {
                if (err) console.log(err);
                else {
                    image.resize(200, 200).write(`public/uploads/thumbnails/thumb_${req.file.originalname}`);
                }
            });
        }

        res.status(201).json({ message: 'File uploaded successfully', filename: req.file.filename });
    } catch (error) {
        fs.removeSync(`uploads/${req.file.filename}`);
        return res.status(500).json({ message: 'Failed to upload file' });
    }
};

app.post('/upload/file', upload.single('file'), saveFile);

const Jimp = require('jimp');